#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2005;
struct big_num {
    int numbers[MAXN];
    int len;
    big_num() {
        len = 0;
        memset(this -> numbers, 0, sizeof(this -> numbers));
    }
    big_num(int l) {
        len = l;
        memset(this -> numbers, 0, sizeof(int) * (l + 5));
    }
    big_num(int l, int x) {
        len = l;
        memset(this -> numbers, 0, sizeof(int) * (l + 5));
        this -> numbers[0] = x;
    }
    big_num(string s) {
        this -> len = s.size();
        for (int i = 0; i < this -> len; i++)
            this -> numbers[i] = s[this -> len - i - 1] - '0';
    }
    big_num operator+(const big_num &b) {
        big_num ans;
        ans = big_num(max(this -> len, b.len));
        for (int i = 0; i < ans.len; i++) {
            ans.numbers[i] += this -> numbers[i] + b.numbers[i];
            if (ans.numbers[i] > 9) {
                ans.numbers[i + 1]++;
                ans.numbers[i] -= 10;
                if (i == ans.len - 1) {
                    ans.len++;
                }
            }
        }
        // while (!ans.numbers[ans.len--]);
        // for (int i = ans.len; i >= 0; i--) cout << ans.numbers[i];
        // cout << endl;
        return ans;
    }
};

int main() {
    int n;
    cin >> n;

    if (n == 1) {
        cout << 1;
        return 0;
    }
    big_num a(1, 1), b(1, 2), c;
    for (int i = 3; i <= n; i++) {
        c = a + b;
        a = b;
        b = c;
    }
    for (int i = b.len - 1; i >= 0; i--) {
        cout << b.numbers[i];
    }
    return 0;
}
